       "'\\n# Customised CNN\\n\\nimport os\\nimport random\\nimport numpy as np\\nimport pandas as pd\\nimport librosa\\nimport torch\\nimport torch.nn as nn\\nimport torch.optim as optim\\nimport wandb  \\nfrom torch.utils.data import Dataset, DataLoader\\nfrom sklearn.metrics import f1_score\\n\\nDATA_SEED = 42\\nTRAINING_SEED = 1234\\nSR = 22050\\nDURATION = 5.0\\nTOP_DB = 20\\nN_MELS = 128\\nN_FFT = 2048\\nHOP_LENGTH = 512\\nBATCH_SIZE = 32\\nEPOCHS = 20\\nLEARNING_RATE = 0.001\\n\\nDATA_ROOT = \\'/kaggle/input/jan-2026-dl-gen-ai-project/messy_mashup\\'\\nGENRES = [\\'blues\\', \\'classical\\', \\'country\\', \\'disco\\', \\'hiphop\\', \\'jazz\\', \\'metal\\', \\'pop\\', \\'reggae\\', \\'rock\\']\\nSTEMS = {\\'drums\\': \\'drums.wav\\', \\'vocals\\': \\'vocals.wav\\', \\'bass\\': \\'bass.wav\\', \\'other\\': \\'other.wav\\'}\\nSTEM_KEYS = [\\'drums\\', \\'vocals\\', \\'bass\\', \\'other\\']\\n\\nrandom.seed(DATA_SEED)\\nnp.random.seed(DATA_SEED)\\nDEVICE = torch.device(\"cuda\" if torch.cuda.is_available() else \"cpu\") \\n\\ndef init_wandb(project_name=\"messy-mashup-cnn\"):\\n    try:\\n        from kaggle_secrets import UserSecretsClient\\n        user_secrets = UserSecretsClient()\\n        wandb_key = user_secrets.get_secret(\"WANDB_API\")\\n        wandb.login(key=wandb_key)\\n        return True\\n    except:\\n        print(\"Logging will be skipped.\")\\n        return False\\n\\n# Train Test Split \\ndef build_dataset(root_dir, val_split=0.17, seed=42):\\n    train_dict = {g: {k: [] for k in STEM_KEYS} for g in GENRES}\\n    val_dict = {g: {k: [] for k in STEM_KEYS} for g in GENRES}\\n    \\n    rng = random.Random(seed)\\n    base_path = os.path.join(root_dir, \\'genres_stems\\')\\n\\n    for genre in GENRES:\\n        genre_path = os.path.join(base_path, genre)\\n        if not os.path.isdir(genre_path): continue\\n\\n        valid_songs = []\\n        for song_folder in sorted(os.listdir(genre_path)):\\n            song_path = os.path.join(genre_path, song_folder)\\n            if not os.path.isdir(song_path): continue\\n\\n            song_stems = {}\\n            is_valid = True\\n            for key, filename in STEMS.items():\\n                stem_path = os.path.join(song_path, filename)\\n                if not os.path.isfile(stem_path) or os.path.getsize(stem_path) < 4096:\\n                    is_valid = False\\n                    break\\n                song_stems[key] = stem_path\\n            \\n            if is_valid: valid_songs.append(song_stems)\\n\\n        rng.shuffle(valid_songs)\\n        split_idx = int(len(valid_songs) * (1 - val_split))\\n        \\n        def add_to_dict(target, songs):\\n            for song in songs:\\n                for key in STEM_KEYS:\\n                    target[genre][key].append(song[key])\\n\\n        add_to_dict(train_dict, valid_songs[:split_idx])\\n        add_to_dict(val_dict, valid_songs[split_idx:])\\n        print(f\"Genre: {genre:10} | Train: {len(valid_songs[:split_idx]):3} | Val: {len(valid_songs[split_idx:]):3}\")\\n\\n    return train_dict, val_dict\\n\\n# Detecting Silence \\ndef find_long_silences(dataset_dict, sr=SR, threshold_sec=DURATION, top_db=TOP_DB):\\n    records = []\\n    all_tasks = [(g, s, p) for g in dataset_dict for s, paths in dataset_dict[g].items() for p in paths]\\n    \\n    for genre, stem, path in all_tasks:\\n        y, _ = librosa.load(path, sr=sr)\\n        intervals = librosa.effects.split(y, top_db=top_db)\\n        \\n        total_silence = 0\\n        if len(intervals) == 0:\\n            total_silence = librosa.get_duration(y=y, sr=sr)\\n        else:\\n            intervals_sec = intervals / sr\\n            total_silence += intervals_sec[0][0] \\n            for i in range(len(intervals_sec)-1):\\n                total_silence += (intervals_sec[i+1][0] - intervals_sec[i][1]) \\n            total_silence += (librosa.get_duration(y=y, sr=sr) - intervals_sec[-1][1]) \\n\\n        if total_silence >= threshold_sec:\\n            records.append({\"Genre\": genre, \"Stem\": stem, \"Total_Silence_Sec\": total_silence, \"File_Path\": path})\\n            \\n    return pd.DataFrame(records)\\n\\n# Dataset Definition\\nclass MashupDataset(Dataset):\\n    def __init__(self, dataset_dict, genres, stem_keys, samples_per_genre=200):\\n        self.dataset_dict = dataset_dict\\n        self.genres = genres\\n        self.stem_keys = stem_keys\\n        self.samples = []\\n\\n        for idx, genre in enumerate(genres):\\n            for _ in range(samples_per_genre):\\n                self.samples.append((idx, genre))\\n\\n    def __len__(self):\\n        return len(self.samples)\\n\\n    def __getitem__(self, idx):\\n        genre_idx, genre_name = self.samples[idx]\\n        mix = np.zeros(int(SR * DURATION))\\n\\n        for key in self.stem_keys:\\n            path = random.choice(self.dataset_dict[genre_name][key])\\n            y, _ = librosa.load(path, sr=SR, duration=DURATION)\\n\\n            if len(y) < len(mix):\\n                y = np.pad(y, (0, len(mix) - len(y)))\\n\\n            mix += y * random.uniform(0.8, 1.2)\\n\\n        mel = librosa.feature.melspectrogram(\\n            y=mix, sr=SR, n_fft=N_FFT, hop_length=HOP_LENGTH, n_mels=N_MELS\\n        )\\n\\n        mel_db = librosa.power_to_db(mel, ref=np.max)\\n        mel_db = (mel_db + 40.0) / 40.0\\n\\n        tensor = torch.tensor(mel_db, dtype=torch.float32).unsqueeze(0)\\n        return tensor, genre_idx\\n\\n# CNN Architecture\\nclass GenreCNN(nn.Module):\\n    def __init__(self, num_classes=len(GENRES)):\\n        super().__init__()\\n        self.features = nn.Sequential(\\n            nn.Conv2d(1, 16, 3, padding=1),\\n            nn.BatchNorm2d(16),\\n            nn.ReLU(),\\n            nn.MaxPool2d(2),\\n            nn.Conv2d(16, 32, 3, padding=1),\\n            nn.BatchNorm2d(32),\\n            nn.ReLU(),\\n            nn.MaxPool2d(2),\\n            nn.Conv2d(32, 64, 3, padding=1),\\n            nn.BatchNorm2d(64),\\n            nn.ReLU(),\\n            nn.MaxPool2d(2),\\n        )\\n        self.classifier = nn.Sequential(\\n            nn.Flatten(),\\n            nn.Linear(64 * 16 * 27, 128),\\n            nn.ReLU(),\\n            nn.Dropout(0.3),\\n            nn.Linear(128, num_classes)\\n        )\\n\\n    def forward(self, x):\\n        x = self.features(x)\\n        return self.classifier(x)\\n\\n# Training/Eval Functions\\ndef train_one_epoch(model, loader, criterion, optimizer):\\n    model.train()\\n    total_loss = 0\\n    for inputs, labels in loader:\\n        inputs, labels = inputs.to(DEVICE), labels.to(DEVICE)\\n        optimizer.zero_grad()\\n        outputs = model(inputs)\\n        loss = criterion(outputs, labels)\\n        loss.backward()\\n        optimizer.step()\\n        total_loss += loss.item()\\n    return total_loss / len(loader)\\n\\ndef evaluate(model, loader):\\n    model.eval()\\n    all_preds, all_labels = [], []\\n    with torch.no_grad():\\n        for inputs, labels in loader:\\n            inputs = inputs.to(DEVICE)\\n            outputs = model(inputs)\\n            preds = torch.argmax(outputs, dim=1)\\n            all_preds.extend(preds.cpu().numpy())\\n            all_labels.extend(labels.numpy())\\n    return f1_score(all_labels, all_preds, average=\\'macro\\')\\n\\ndef main():\\n    # Dataset Prep\\n    train_dict, val_dict = build_dataset(DATA_ROOT)\\n    train_loader = DataLoader(MashupDataset(train_dict, GENRES, STEM_KEYS), batch_size=BATCH_SIZE, shuffle=True)\\n    val_loader = DataLoader(MashupDataset(val_dict, GENRES, STEM_KEYS, samples_per_genre=50), batch_size=BATCH_SIZE)\\n\\n    # WandB Initialization\\n    tracking_enabled = init_wandb()\\n    if tracking_enabled:\\n        wandb.init(\\n            project=\"messy-mashup-cnn\",\\n            name=f\"cnn-v4-run-{pd.Timestamp.now().strftime(\\'%m%d-%H%M\\')}\",\\n            config={\\n                \"batch_size\": BATCH_SIZE,\\n                \"epochs\": EPOCHS,\\n                \"lr\": LEARNING_RATE,\\n                \"n_mels\": N_MELS,\\n                \"architecture\": \"CNN-Simple-Audio\"\\n            }\\n        )\\n\\n    # Model Setup\\n    model = GenreCNN().to(DEVICE)\\n    criterion = nn.CrossEntropyLoss()\\n    optimizer = optim.Adam(model.parameters(), lr=LEARNING_RATE)\\n\\n    # Training Loop with WandB Logging\\n    for epoch in range(EPOCHS):\\n        train_loss = train_one_epoch(model, train_loader, criterion, optimizer)\\n        val_f1 = evaluate(model, val_loader)\\n        \\n        # Log to Console\\n        print(f\"Epoch {epoch+1}/{EPOCHS} | Loss: {train_loss:.4f} | Val Macro F1: {val_f1:.4f}\")\\n        \\n        # Log to WandB\\n        if tracking_enabled:\\n            wandb.log({\\n                \"epoch\": epoch + 1,\\n                \"train_loss\": train_loss,\\n                \"val_f1_macro\": val_f1\\n            })\\n\\n    # Model Saving \\n    torch.save(model.state_dict(), \"genre_cnn.pth\")\\n    if tracking_enabled:\\n        artifact = wandb.Artifact(\"trained_cnn_model\", type=\"model\")\\n        artifact.add_file(\"genre_cnn.pth\")\\n        wandb.log_artifact(artifact)\\n        wandb.finish() \\n\\nif __name__ == \"__main__\":\\n    main()\\n'"
